const fs = require('fs');

let c = fs.readFileSync('apps/web/src/components/widgets/WidgetRenderer.tsx', 'utf8');

const imports = [
"// NEW AUTOGENERATED IMPORTS",
"import { GymPEText, GymPEWeather, GymPECalendar, GymPEAnnouncement, GymPETicker } from './themes/gym-pe';",
"import { PrincipalsOfficeLogo, PrincipalsOfficeText, PrincipalsOfficeClock, PrincipalsOfficeAnnouncement, PrincipalsOfficeRichText, PrincipalsOfficeTicker } from './themes/principals-office';",
"import { OfficeDashboardLogo, OfficeDashboardText, OfficeDashboardClock, OfficeDashboardAnnouncement, OfficeDashboardStaff, OfficeDashboardCalendar, OfficeDashboardTicker } from './themes/office-dashboard';"
].join('\n');

c = c.replace(/} from 'lucide-react';/, "} from 'lucide-react';\n" + imports);

// We need to inject these lines into the correct widget components
const injections = {
  'TextWidget': [
    "  if (config.theme === 'gym-pe') return <GymPEText config={config} />;",
    "  if (config.theme === 'principals-office') return <PrincipalsOfficeText config={config} />;",
    "  if (config.theme === 'office-dashboard') return <OfficeDashboardText config={config} />;"
  ],
  'WeatherWidget': [
    "  if (config.theme === 'gym-pe') return <GymPEWeather config={config} compact={compact} />;"
  ],
  'CalendarWidget': [
    "  if (config.theme === 'gym-pe') return <GymPECalendar config={config} compact={compact} />;",
    "  if (config.theme === 'office-dashboard') return <OfficeDashboardCalendar config={config} compact={compact} />;"
  ],
  'AnnouncementWidget': [
    "  if (config.theme === 'gym-pe') return <GymPEAnnouncement config={config} compact={compact} />;",
    "  if (config.theme === 'principals-office') return <PrincipalsOfficeAnnouncement config={config} compact={compact} />;",
    "  if (config.theme === 'office-dashboard') return <OfficeDashboardAnnouncement config={config} compact={compact} />;"
  ],
  'TickerWidget': [
    "  if (config.theme === 'gym-pe') return <GymPETicker config={config} />;",
    "  if (config.theme === 'principals-office') return <PrincipalsOfficeTicker config={config} />;",
    "  if (config.theme === 'office-dashboard') return <OfficeDashboardTicker config={config} />;"
  ],
  'ImageWidget': [
    "  if (config.theme === 'principals-office') return <PrincipalsOfficeLogo config={config} />;",
    "  if (config.theme === 'office-dashboard') return <OfficeDashboardLogo config={config} />;"
  ],
  'ClockWidget': [
    "  if (config.theme === 'principals-office') return <PrincipalsOfficeClock config={config} compact={compact} />;",
    "  if (config.theme === 'office-dashboard') return <OfficeDashboardClock config={config} compact={compact} />;"
  ],
  'StaffSpotlightWidget': [
    "  if (config.theme === 'office-dashboard') return <OfficeDashboardStaff config={config} compact={compact} />;"
  ]
};

for (const funcName of Object.keys(injections)) {
  const lines = injections[funcName];
  const searchStr = "function " + funcName + "({ config, compact }: { config: any; compact: boolean }) {";
  const searchStr2 = "function " + funcName + "({ config }: { config: any }) {";
  
  if (c.includes(searchStr)) {
    c = c.replace(searchStr, searchStr + '\n' + lines.join('\n'));
  } else if (c.includes(searchStr2)) {
    const linesNoCompact = lines.map(l => l.replace(/ compact=\{compact\}/g, ''));
    c = c.replace(searchStr2, searchStr2 + '\n' + linesNoCompact.join('\n'));
  } else {
    console.log('Failed to find', funcName);
  }
}

// Special case for RichText Widget (missing in standard injections before)
const richTextSearch = "function RichTextWidget({ config }: { config: any }) {";
if (c.includes(richTextSearch)) {
  c = c.replace(richTextSearch, richTextSearch + "\n  if (config.theme === 'principals-office') return <PrincipalsOfficeRichText config={config} />;");
} else {
  // It's under TextWidget? Wait, I added LibraryQuietRichText to TextWidget earlier.
  // Let's check if there's a RichTextWidget or if it's handled by TextWidget
}

fs.writeFileSync('apps/web/src/components/widgets/WidgetRenderer.tsx', c);
console.log('Done 3 themes');
